python3 << 'PYEOF'
import pandas as pd
import json

df = pd.read_csv('market.csv')
active = df[df['is_resolved'] == False].copy()

results = []
for _, row in active.iterrows():
    qid = row['qid']
    title = row['title']
    market_str = row['market_aggregate']

    # Parse market aggregate
    outcomes = {}
    if pd.notna(market_str):
        try:
            outcomes = json.loads(market_str.replace("'", '"'))
        except:
            outcomes = {}

    # If no outcomes, try the options column
    if not outcomes and pd.notna(row.get('options', None)):
        try:
            opts = json.loads(str(row['options']).replace("'", '"'))
            if isinstance(opts, list):
                outcomes = {o: 1.0/len(opts) for o in opts}
        except:
            outcomes = {}

    # Normalize to sum to 1.0, max 5 outcomes
    if outcomes:
        # Sort by probability, keep top 5
        sorted_items = sorted(outcomes.items(), key=lambda x: x[1], reverse=True)[:5]
        total = sum(x[1] for x in sorted_items)
        if total > 0:
            sorted_items = [(k, v/total) for k, v in sorted_items]
        outcomes = dict(sorted_items)

    results.append({
        'qid': qid,
        'title': title[:120],
        'resolution_date': str(row['resolution_date']),
        'outcomes': outcomes
    })

with open('memory/all_predictions.json', 'w') as f:
    json.dump(results, f, indent=2)

print(f"Exported {len(results)} questions")
# Show first 5
for r in results[:5]:
    print(f"  {r['qid']}: {r['outcomes']}")
PYEOF

